import re
from datetime import datetime

# Load the full review dataset
reviews_result = var_functions.query_db:8

# Let's check what reviews we have in the date range
# Convert date strings to datetime objects for proper comparison
def parse_date(date_str):
    """Parse various date formats"""
    if not date_str or date_str == 'None':
        return None

    # Try different formats
    formats = [
        '%Y-%m-%d %H:%M:%S',
        '%Y-%m-%d %H:%M:%S.%f',
        '%B %d, %Y at %I:%M %p',
        '%d %B %Y, %H:%M',
        '%d %b %Y, %H:%M',
        '%Y-%m-%d %H:%M'
    ]

    for fmt in formats:
        try:
            return datetime.strptime(date_str, fmt)
        except:
            continue

    # Try to extract date parts manually for edge cases
    try:
        # Extract year, month, day from various formats
        year_match = re.search(r'\b(201\d|202\d)\b', date_str)
        month_match = re.search(r'\b(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\w*\b', date_str)
        day_match = re.search(r'\b(\d{1,2})\b', date_str)

        if year_match and month_match and day_match:
            year = int(year_match.group(1))
            month_str = month_match.group(1)
            day = int(day_match.group(1))

            month_map = {
                'Jan': 1, 'Feb': 2, 'Mar': 3, 'Apr': 4, 'May': 5, 'Jun': 6,
                'Jul': 7, 'Aug': 8, 'Sep': 9, 'Oct': 10, 'Nov': 11, 'Dec': 12
            }

            for key, val in month_map.items():
                if month_str.startswith(key):
                    month = val
                    break
            else:
                return None

            return datetime(year, month, day)
    except:
        pass

    return None

# Define date range
start_date = datetime(2016, 1, 1)
end_date = datetime(2016, 6, 30, 23, 59, 59)

# Filter reviews in date range
filtered_reviews = []
for review in reviews_result:
    date_obj = parse_date(review['date'])
    if date_obj and start_date <= date_obj <= end_date:
        filtered_reviews.append({
            'business_ref': review['business_ref'],
            'rating': int(review['rating']),
            'date': date_obj
        })

print('__RESULT__:')
print(json.dumps({
    'total_reviews_in_range': len(filtered_reviews),
    'sample_reviews': filtered_reviews[:5]
}))"}

{"code": "import json
import re
from datetime import datetime

# Load the review data from storage
reviews_data = locals()['var_functions.query_db:8']

# Parse date function to handle various formats
def parse_date(date_str):
    if not date_str or date_str == 'None':
        return None

    formats = [
        '%Y-%m-%d %H:%M:%S',
        '%B %d, %Y at %I:%M %p',
        '%d %B %Y, %H:%M',
        '%d %b %Y, %H:%M',
        '%Y-%m-%d %H:%M'
    ]

    for fmt in formats:
        try:
            return datetime.strptime(date_str, fmt)
        except:
            continue

    return None

# Define date range
start_date = datetime(2016, 1, 1)
end_date = datetime(2016, 6, 30, 23, 59, 59)

# Filter reviews in the date range
filtered_reviews = []
for review in reviews_data:
    date_obj = parse_date(review['date'])
    if date_obj and start_date <= date_obj <= end_date:
        filtered_reviews.append({
            'business_ref': review['business_ref'],
            'rating': int(review['rating']),
            'date': str(date_obj)
        })

# Group by business and calculate average rating and count
from collections import defaultdict
business_stats = defaultdict(lambda: {'ratings': [], 'count': 0})

for review in filtered_reviews:
    business_ref = review['business_ref']
    business_stats[business_ref]['ratings'].append(review['rating'])
    business_stats[business_ref]['count'] += 1

# Calculate averages and filter businesses with at least 5 reviews
business_averages = []
for business_ref, stats in business_stats.items():
    if stats['count'] >= 5:
        avg_rating = sum(stats['ratings']) / stats['count']
        business_averages.append({
            'business_ref': business_ref,
            'avg_rating': avg_rating,
            'review_count': stats['count']
        })

# Sort by average rating descending
business_averages.sort(key=lambda x: x['avg_rating'], reverse=True)

top_5 = business_averages[:5]
result = {
    'total_filtered_reviews': len(filtered_reviews),
    'businesses_with_5plus_reviews': len(business_averages),
    'top_5_businesses': top_5
}

print('__RESULT__:')
print(json.dumps(result))"}

